<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Kanban Board</title>
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body {
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
      background: #f4f5f7;
      min-height: 100vh;
      padding: 24px;
    }
    .board {
      display: grid;
      grid-template-columns: repeat(3, 1fr);
      gap: 16px;
      max-width: 1200px;
      margin: 0 auto;
    }
    .column {
      background: #ebecf0;
      border-radius: 12px;
      display: flex;
      flex-direction: column;
      min-height: 500px;
    }
    .column-header {
      display: flex;
      align-items: center;
      justify-content: space-between;
      padding: 16px;
      font-weight: 600;
      font-size: 14px;
      text-transform: uppercase;
      letter-spacing: 0.5px;
      color: #172b4d;
    }
    .column-header .count {
      background: #0052cc;
      color: white;
      font-size: 12px;
      font-weight: 600;
      padding: 2px 8px;
      border-radius: 12px;
      min-width: 24px;
      text-align: center;
    }
    .card-container {
      flex: 1;
      padding: 0 12px 12px;
      overflow-y: auto;
      min-height: 200px;
      display: flex;
      flex-direction: column;
      gap: 8px;
    }
    .card-container.drag-over {
      background: rgba(0, 82, 204, 0.1);
      border-radius: 8px;
    }
    .card {
      background: white;
      border-radius: 8px;
      padding: 12px;
      box-shadow: 0 1px 2px rgba(9, 30, 66, 0.15);
      cursor: grab;
      display: flex;
      justify-content: space-between;
      align-items: flex-start;
      gap: 8px;
      transition: box-shadow 0.15s ease, transform 0.15s ease;
      user-select: none;
    }
    .card:hover {
      box-shadow: 0 4px 8px rgba(9, 30, 66, 0.15);
      transform: translateY(-1px);
    }
    .card:active, .card.dragging {
      cursor: grabbing;
      box-shadow: 0 8px 16px rgba(9, 30, 66, 0.2);
      transform: translateY(-2px);
    }
    .card.dragging {
      opacity: 0.5;
    }
    .card-title {
      flex: 1;
      font-size: 14px;
      line-height: 1.4;
      color: #172b4d;
      word-wrap: break-word;
    }
    .card-del {
      background: transparent;
      border: none;
      color: #6b778c;
      cursor: pointer;
      padding: 4px;
      border-radius: 4px;
      display: flex;
      align-items: center;
      justify-content: center;
      flex-shrink: 0;
      transition: background 0.15s ease, color 0.15s ease;
    }
    .card-del:hover {
      background: #ffebe9;
      color: #de350b;
    }
    .card-del:focus-visible {
      outline: 2px solid #0052cc;
      outline-offset: 2px;
    }
    .add-card-form {
      max-width: 1200px;
      margin: 0 auto 24px;
      display: flex;
      gap: 12px;
    }
    #new-card {
      flex: 1;
      padding: 12px 16px;
      border: 2px solid #dfe1e6;
      border-radius: 8px;
      font-size: 14px;
      font-family: inherit;
      transition: border-color 0.15s ease, box-shadow 0.15s ease;
    }
    #new-card:focus {
      outline: none;
      border-color: #0052cc;
      box-shadow: 0 0 0 3px rgba(0, 82, 204, 0.15);
    }
    #add-card {
      background: #0052cc;
      color: white;
      border: none;
      border-radius: 8px;
      padding: 12px 24px;
      font-size: 14px;
      font-weight: 600;
      font-family: inherit;
      cursor: pointer;
      transition: background 0.15s ease;
    }
    #add-card:hover {
      background: #0065ff;
    }
    #add-card:active {
      background: #0043a0;
    }
    #add-card:focus-visible {
      outline: 2px solid #0052cc;
      outline-offset: 2px;
    }
    @media (max-width: 900px) {
      .board { grid-template-columns: 1fr; }
      .column { min-height: 300px; }
    }
  </style>
</head>
<body>
  <form class="add-card-form" id="add-card-form">
    <input type="text" id="new-card" placeholder="Enter card title..." aria-label="New card title">
    <button type="submit" id="add-card">Add Card</button>
  </form>

  <div class="board">
    <section class="column" id="col-todo" data-column="todo">
      <header class="column-header">
        <span>To Do</span>
        <span class="count">0</span>
      </header>
      <div class="card-container" role="list" aria-label="To Do cards"></div>
    </section>
    <section class="column" id="col-doing" data-column="doing">
      <header class="column-header">
        <span>Doing</span>
        <span class="count">0</span>
      </header>
      <div class="card-container" role="list" aria-label="Doing cards"></div>
    </section>
    <section class="column" id="col-done" data-column="done">
      <header class="column-header">
        <span>Done</span>
        <span class="count">0</span>
      </header>
      <div class="card-container" role="list" aria-label="Done cards"></div>
    </section>
  </div>

  <script>
    (function() {
      const STORAGE_KEY = 'kanban-board-state';
      let cardIdCounter = 0;

      const columns = {
        todo: document.querySelector('#col-todo .card-container'),
        doing: document.querySelector('#col-doing .card-container'),
        done: document.querySelector('#col-done .card-container')
      };

      const columnElements = {
        todo: document.getElementById('col-todo'),
        doing: document.getElementById('col-doing'),
        done: document.getElementById('col-done')
      };

      function generateId() {
        return 'card-' + ++cardIdCounter + '-' + Date.now();
      }

      function createCardElement(card) {
        const cardEl = document.createElement('article');
        cardEl.className = 'card';
        cardEl.draggable = true;
        cardEl.dataset.id = card.id;
        cardEl.dataset.column = card.column;
        cardEl.setAttribute('role', 'listitem');
        cardEl.innerHTML = `
          <span class="card-title">${escapeHtml(card.title)}</span>
          <button type="button" class="card-del" aria-label="Delete card" title="Delete">
            <svg width="16" height="16" viewBox="0 0 16 16" fill="currentColor" aria-hidden="true">
              <path d="M5.5 3.5A.5.5 0 0 1 6 3h4a.5.5 0 0 1 .5.5v1H6v-1zm-1 1v8a1 1 0 0 0 1 1h4a1 1 0 0 0 1-1V4.5H4.5zm10 .5a.5.5 0 0 1 .5.5v8a.5.5 0 0 1-1 0V5a.5.5 0 0 1 .5-.5z"/>
            </svg>
          </button>
        `;

        const deleteBtn = cardEl.querySelector('.card-del');
        deleteBtn.addEventListener('click', (e) => {
          e.stopPropagation();
          deleteCard(card.id);
        });

        cardEl.addEventListener('dragstart', handleDragStart);
        cardEl.addEventListener('dragend', handleDragEnd);

        return cardEl;
      }

      function escapeHtml(text) {
        const div = document.createElement('div');
        div.textContent = text;
        return div.innerHTML;
      }

      function updateCounts() {
        Object.keys(columns).forEach(key => {
          const count = columns[key].children.length;
          const countEl = columnElements[key].querySelector('.count');
          countEl.textContent = count;
        });
      }

      function saveState() {
        const state = [];
        Object.keys(columns).forEach(columnKey => {
          Array.from(columns[columnKey].children).forEach(cardEl => {
            state.push({
              id: cardEl.dataset.id,
              title: cardEl.querySelector('.card-title').textContent,
              column: columnKey
            });
          });
        });
        localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
      }

      function loadState() {
        const saved = localStorage.getItem(STORAGE_KEY);
        if (!saved) return;
        try {
          const state = JSON.parse(saved);
          state.forEach(card => {
            if (columns[card.column]) {
              const cardEl = createCardElement(card);
              columns[card.column].appendChild(cardEl);
              const idNum = parseInt(card.id.split('-')[1], 10);
              if (idNum > cardIdCounter) cardIdCounter = idNum;
            }
          });
          updateCounts();
        } catch (e) {
          console.error('Failed to load board state:', e);
        }
      }

      function addCard(title) {
        const trimmed = title.trim();
        if (!trimmed) return;
        const card = { id: generateId(), title: trimmed, column: 'todo' };
        const cardEl = createCardElement(card);
        columns.todo.appendChild(cardEl);
        updateCounts();
        saveState();
      }

      function deleteCard(id) {
        const cardEl = document.querySelector(`.card[data-id="${id}"]`);
        if (cardEl) {
          cardEl.remove();
          updateCounts();
          saveState();
        }
      }

      function moveCard(cardEl, targetColumnKey) {
        const sourceColumnKey = cardEl.dataset.column;
        if (sourceColumnKey === targetColumnKey) return;
        columns[targetColumnKey].appendChild(cardEl);
        cardEl.dataset.column = targetColumnKey;
        updateCounts();
        saveState();
      }

      let draggedCard = null;

      function handleDragStart(e) {
        draggedCard = this;
        this.classList.add('dragging');
        e.dataTransfer.effectAllowed = 'move';
        e.dataTransfer.setData('text/plain', this.dataset.id);
      }

      function handleDragEnd() {
        this.classList.remove('dragging');
        draggedCard = null;
        Object.values(columns).forEach(col => col.classList.remove('drag-over'));
      }

      function handleDragOver(e) {
        e.preventDefault();
        e.dataTransfer.dropEffect = 'move';
        const container = this.closest('.card-container');
        if (container) container.classList.add('drag-over');
      }

      function handleDragLeave(e) {
        const container = this.closest('.card-container');
        if (container && !container.contains(e.relatedTarget)) {
          container.classList.remove('drag-over');
        }
      }

      function handleDrop(e) {
        e.preventDefault();
        const container = this.closest('.card-container');
        if (!container || !draggedCard) return;
        container.classList.remove('drag-over');
        const columnKey = container.parentElement.dataset.column;
        moveCard(draggedCard, columnKey);
      }

      Object.values(columns).forEach(container => {
        container.addEventListener('dragover', handleDragOver);
        container.addEventListener('dragleave', handleDragLeave);
        container.addEventListener('drop', handleDrop);
      });

      document.getElementById('add-card-form').addEventListener('submit', (e) => {
        e.preventDefault();
        const input = document.getElementById('new-card');
        addCard(input.value);
        input.value = '';
        input.focus();
      });

      loadState();
    })();
  </script>
</body>
</html>
